const data = $input.first().json;
const config = $('Set Config').first().json;
const SKIP = ['.pdf','twitter.com','x.com','facebook.com','instagram.com','tiktok.com','youtube.com','reddit.com'];
const results = (data.organic_results || []).filter(r => !SKIP.some(s => (r.link || '').toLowerCase().includes(s))).slice(0, config.numSources);
if (results.length === 0) throw new Error('No valid URLs found for topic: ' + config.topic);
return results.map((r, i) => ({json:{urlIndex:i+1,url:r.link,title:r.title||'',snippet:r.snippet||'',topic:config.topic,recipientEmail:config.recipientEmail,runId:config.runId}}));

const item = $input.first().json;
const orig = $('Loop Over URLs').first().json;
const raw = item.body || item.data || '';
return [{json:{...orig,content:raw.substring(0,14000),contentLength:raw.length,scrapeMethod:'jina',scrapeOk:!item.error&&raw.length>300}}];

