const text = $input.first().json.text;
const orig = $('Normalize Firecrawl').first().json;
return [{json:{...orig,text}}];

const agg = $input.first().json;
const summaries = agg.pageSummaries || [];
const topic = (summaries[0] || {}).topic || 'Unknown Topic';
const recipientEmail = (summaries[0] || {}).recipientEmail || '';
const runId = (summaries[0] || {}).runId || '';
const parsed = summaries.map(s => { try { return JSON.parse(s.text); } catch(e) { return {status:'parse_error',summary:String(s.text)}; } });
const ok = parsed.filter(p => p.status === 'ok').length;
const evidence = parsed.map((p, i) => {
  const src = summaries[i];
  if (p.status !== 'ok') return 'SOURCE ' + (i+1) + ': ' + src.url + '
STATUS: Unavailable';
  return 'SOURCE ' + (i+1) + ': ' + src.url + '
TITLE: ' + (p.title||'') + '
SUMMARY: ' + p.summary + '
KEY POINTS: ' + (p.keyPoints||[]).join(' | ') + '
DATA: ' + (p.dataPoints||[]).join(' | ') + '
RELEVANCE: ' + p.relevance;
}).join('

---

');
const prompt = 'You are a senior research analyst.

RESEARCH TOPIC: ' + topic + '
SOURCES: ' + summaries.length + ' analyzed, ' + ok + ' retrieved
DATE: ' + new Date().toLocaleDateString("en-US",{year:"numeric",month:"long",day:"numeric"}) + '

EVIDENCE:
' + evidence + '

Write a professional executive research report in Markdown with these sections:
# Executive Report: ' + topic + '
## Executive Summary
## Key Findings
## Detailed Analysis
## Data & Evidence
## Conclusions & Recommendations
## Sources

RULES: Only include facts from the evidence. Do not invent statistics. Cite sources by number.';
return [{json:{synthesisPrompt:prompt,topic,recipientEmail,runId,sourceCount:summaries.length,successCount:ok}}];

const data = $input.first().json;
const synth = $('Build Synthesis Prompt').first().json;
const md = data.text || '';
const topic = synth.topic || 'Research Report';
const runId = synth.runId || '';
const date = new Date().toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'});

const toHtml = s => {
  const lines = s.split('\n');
  const out = [];
  let i = 0;
  let inList = false;
  while (i < lines.length) {
    const line = lines[i];
    if (i + 1 < lines.length && /^\|/.test(line) && /^\|[\s\-|:]+\|/.test(lines[i+1])) {
      if (inList) { out.push('</ul>'); inList = false; }
      const headers = line.split('|').slice(1,-1).map(h => '<th>' + h.trim() + '</th>').join('');
      out.push('<table><thead><tr>' + headers + '</tr></thead><tbody>');
      i += 2;
      while (i < lines.length && /^\|/.test(lines[i])) {
        const cells = lines[i].split('|').slice(1,-1).map(c => '<td>' + c.trim().replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>') + '</td>').join('');
        out.push('<tr>' + cells + '</tr>');
        i++;
      }
      out.push('</tbody></table>');
      continue;
    }
    if (/^### /.test(line)) { if (inList) { out.push('</ul>'); inList = false; } out.push('<h3>' + line.slice(4) + '</h3>'); }
    else if (/^## /.test(line)) { if (inList) { out.push('</ul>'); inList = false; } out.push('<h2>' + line.slice(3) + '</h2>'); }
    else if (/^# /.test(line)) { if (inList) { out.push('</ul>'); inList = false; } out.push('<h1>' + line.slice(2) + '</h1>'); }
    else if (/^[-*] /.test(line) || /^\d+\. /.test(line)) {
      if (!inList) { out.push('<ul>'); inList = true; }
      const content = line.replace(/^[-*] /,'').replace(/^\d+\. /,'').replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>').replace(/`(.+?)`/g,'<code>$1</code>');
      out.push('<li>' + content + '</li>');
    } else if (/^---+$/.test(line.trim())) { if (inList) { out.push('</ul>'); inList = false; } out.push('<hr>'); }
    else if (line.trim() === '') { if (inList) { out.push('</ul>'); inList = false; } }
    else { if (inList) { out.push('</ul>'); inList = false; } const content = line.replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>').replace(/`(.+?)`/g,'<code>$1</code>').replace(/^> /,''); out.push('<p>' + content + '</p>'); }
    i++;
  }
  if (inList) out.push('</ul>');
  return out.join('\n');
};

const body = toHtml(md);
const html = `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><title>${topic}</title><style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:Georgia,serif;color:#1a1a2e;padding:40px;max-width:900px;margin:0 auto;font-size:14px}h1{font-size:24px;border-bottom:3px solid #0f3460;padding-bottom:10px;margin:0 0 20px}h2{font-size:18px;color:#0f3460;margin:24px 0 10px;border-left:4px solid #e94560;padding-left:10px}h3{font-size:15px;margin:16px 0 8px}p{line-height:1.7;margin-bottom:10px}ul{margin:10px 0 14px 20px;list-style:disc}li{line-height:1.7;margin-bottom:6px}ol{margin:10px 0 14px 20px}hr{border:none;border-top:1px solid #dee2e6;margin:20px 0}table{width:100%;border-collapse:collapse;margin:16px 0;font-size:13px}th{background:#0f3460;color:#fff;padding:8px 12px;text-align:left;font-weight:600}td{padding:7px 12px;border-bottom:1px solid #dee2e6}tr:nth-child(even) td{background:#f8f9fa}code{background:#f0f0f0;padding:1px 5px;border-radius:3px;font-size:12px}strong{font-weight:700}.meta{background:#f8f9fa;border:1px solid #dee2e6;border-radius:6px;padding:12px 18px;margin-bottom:24px;font-size:12px;color:#666}.footer{margin-top:40px;padding-top:14px;border-top:1px solid #dee2e6;font-size:11px;color:#999;text-align:center}</style></head><body><div class="meta">Date: ${date} &nbsp;|&nbsp; Topic: ${topic} &nbsp;|&nbsp; Run: ${runId} &nbsp;|&nbsp; Sources: ${synth.sourceCount||'?'} (${synth.successCount||'?'} retrieved)</div>${body}<div class="footer">Generated by Self-Healing Research Agent | n8n Workflow</div></body></html>`;
return [{json:{html,topic,recipientEmail:synth.recipientEmail,runId,sourceCount:synth.sourceCount,successCount:synth.successCount}}];
